import apMicroeconomics from './ap-microeconomics.js'

const rotate = (items, offset) => items.map((_, index) => items[(index + offset) % items.length])
let answerCounter = 0

const problems = checks => checks.map(check => {
  const target = answerCounter++ % 4
  const offset = (4 - target) % 4
  return {
    type: 'mc',
    question: { en: check[0], zh: check[1] },
    choices: rotate(check[2], offset),
    answer: target,
    explanation: { en: check[3], zh: check[4] },
  }
})

const lesson = config => ({
  id: config.id,
  title: config.title,
  titleZh: config.titleZh,
  content: [
    { type: 'h2', en: config.heading, zh: config.headingZh },
    { type: 'p', en: config.intro, zh: config.introZh },
    { type: 'h3', en: 'Model and causal mechanism', zh: '模型与因果机制' },
    { type: 'p', en: config.model, zh: config.modelZh },
    ...(config.math || []).map(tex => ({ type: 'math', tex })),
    { type: 'h3', en: 'Graphing, calculation, and AP reasoning', zh: '作图、计算与 AP 推理' },
    { type: 'p', en: config.skill, zh: config.skillZh },
    { type: 'p', en: 'Learn the complete model before using exam weighting to plan review. For each topic, practice the four AP skills: define the principle, interpret an outcome, manipulate the model after a change, and draw or read an accurately labeled graph. A strong response traces a full causal chain—initial change, curve or equation affected, adjustment process, and final effect—while holding other determinants constant. Unit weights guide the number of review questions; they never make a required concept optional.', zh: '应先完整学习模型，再用考试占比安排复习。每个主题都要练习 AP 四类技能：定义原理、解释结果、在条件变化后推演模型，以及绘制或读取标注正确的图形。高质量回答要给出完整因果链——初始变化、受影响的曲线或方程、调整过程与最终结果——并保持其他决定因素不变。单元占比只指导复习题量，绝不意味着某个必学概念可以跳过。' },
    { type: 'note', en: config.note, zh: config.noteZh },
    ...config.examples.map((example, index) => ({
      type: 'example',
      title: { en: `Worked Example ${index + 1}`, zh: `例题 ${index + 1}` },
      problem: { en: example[0], zh: example[1] },
      solution: [
        { type: 'p', en: example[2], zh: example[3] },
        ...(example[4] ? [{ type: 'math', tex: example[4] }] : []),
      ],
    })),
  ],
  problems: problems(config.checks),
})

